sp_widget.client_script:
api.controller = function($scope, spUtil, $timeout, $window, $interval) {
    var c = this;

	// ==========================================
// 双模式初始化
// ==========================================
c.is_guest = c.data.is_guest || false;
c.auth_mode = c.data.auth_mode || 'authenticated';
c.guest_token = '';

// 游客初始化
function initGuestMode() {
    // 1. 先尝试从 localStorage 恢复 token
    var savedToken = '';
    try {
        savedToken = $window.localStorage.getItem('kokoro_guest_token') || '';
    } catch (e) {}

    console.log('📍 游客模式初始化，localStorage中的token:', savedToken);

    // 2. 调用服务端验证或生成新 token
    c.server.get({
        action: 'guest_init',  // ✅ 正确的 action
        guest_token: savedToken
    }).then(function(r) {
        if (r && r.data && r.data.success) {
            c.guest_token = r.data.guest_token;
            c.auth_mode = r.data.auth_mode;

            console.log('✅ 服务端返回的 guest_token:', c.guest_token);

            // 3. 持久化到 localStorage
            try {
                $window.localStorage.setItem('kokoro_guest_token', c.guest_token);
                console.log('✅ guest_token 已保存到 localStorage');
            } catch (e) {
                console.error('❌ 无法保存到 localStorage:', e);
            }

            if (r.data.upgrade_hint) {
                showSuccess('以前のゲストデータがあります。ログインすると移行できます。');
            }

            // 4. 初始化后立即加载历史记录
            $timeout(function() {
                c.server.get({
                    action: 'get_my_history',
                    guest_token: c.guest_token
                }).then(function(historyR) {
                    if (historyR && historyR.data && historyR.data.my_requests) {
                        c.data.my_requests = historyR.data.my_requests;
                        console.log('✅ 游客历史记录已加载:', c.data.my_requests.length);
                    }
                });
            }, 500);

        } else {
            console.error('❌ guest_init 失败');
        }
    }).catch(function(error) {
        console.error('❌ guest_init 请求失败:', error);
    });
}

// 如果是游客模式，立即初始化
if (c.is_guest) {
    initGuestMode();
}

    // ==========================================
    // [新增] 好友守护系统
    // ==========================================

    c.show_guardian = false;
    c.guardian_tab = 'friends'; // friends / requests / search
    c.selected_friend = null;
    c.search_query = "";
    c.search_results = [];
    c.recommended_friends = [];

    c.toggleGuardianCircle = function() {
    c.showMenu = false;

    if (c.is_guest) {
        c.show_login_prompt = true;
        c.login_prompt_feature = 'guardian';
        return;
    }

    c.show_guardian = !c.show_guardian;

    if (c.show_guardian) {
        c.loadGuardianData();
    }
};

// 新增: 登录提示
c.show_login_prompt = false;
c.login_prompt_feature = '';

c.dismissLoginPrompt = function() {
    c.show_login_prompt = false;
};

c.goToLogin = function() {
    $window.location.href = '/login.do?sysparm_goto_url=' + 
        encodeURIComponent($window.location.href);
};

    // 加载守护圈数据
    c.loadGuardianData = function() {
        c.server.get({
            action: 'get_guardian_data'
        }).then(function(r) {
            if (handleServerResponse(r, function(data) {
                    c.data.friends = data.friends || [];
                    c.data.friend_requests = data.friend_requests || [];
                    c.data.friend_notifications = data.notification_count || 0;
                    c.recommended_friends = data.recommended || [];
                }));
        });
    };

    // 搜索用户
    var searchTimer = null;
    c.searchUsers = function() {
        if (searchTimer) $timeout.cancel(searchTimer);

        if (!c.search_query || c.search_query.trim().length < 2) {
            c.search_results = [];
            return;
        }

        searchTimer = $timeout(function() {
            c.server.get({
                action: 'search_users',
                query: c.search_query
            }).then(function(r) {
                if (handleServerResponse(r, function(data) {
                        c.search_results = data.results || [];
                    }));
            });
        }, 500);
    };

    // 发送好友请求
    c.sendFriendRequest = function(user) {
        if (user.already_friend || user.request_sent) return;

        safeServerGet({
    action: 'send_friend_request',
            friend_id: user.sys_id
        }).then(function(r) {
            if (handleServerResponse(r, function() {
                    user.request_sent = true;
                    showSuccess('友達リクエストを送信しました');
                }));
        });
    };

    // 接受好友请求
    c.acceptFriendRequest = function(req) {
        safeServerGet({
    action: 'accept_friend_request',
            request_id: req.sys_id
        }).then(function(r) {
            if (handleServerResponse(r, function() {
                    var index = c.data.friend_requests.indexOf(req);
                    if (index !== -1) {
                        c.data.friend_requests.splice(index, 1);
                    }
                    c.loadGuardianData();
                    showSuccess(req.from_user_name + ' と友達になりました');
                }));
        });
    };

    // 拒绝好友请求
    c.rejectFriendRequest = function(req) {
        safeServerGet({
    action: 'reject_friend_request',
            request_id: req.sys_id
        }).then(function(r) {
            if (handleServerResponse(r, function() {
                    var index = c.data.friend_requests.indexOf(req);
                    if (index !== -1) {
                        c.data.friend_requests.splice(index, 1);
                    }
                    showSuccess('リクエストを拒否しました');
                }));
        });
    };

    // 显示好友详情
    c.showFriendDetail = function(friend) {
        c.selected_friend = friend;
    };

    // 紧急呼叫
    c.emergencyCall = function(friend, $event) {
        if ($event) $event.stopPropagation();

        if (confirm(friend.display_name + ' に緊急呼び出しを送信しますか？')) {
            safeServerGet({
    action: 'send_emergency_call',
                friend_id: friend.user_id
            }).then(function(r) {
                if (handleServerResponse(r, function() {
                        showSuccess('緊急呼び出しを送信しました');
                    }));
            });
        }
    };

    // 发送消息
    c.sendMessage = function(friend, $event) {
        if ($event) $event.stopPropagation();

        var message = prompt(friend.display_name + ' へのメッセージ:');
        if (message && message.trim()) {
            safeServerGet({
    action: 'send_friend_message',
                friend_id: friend.user_id,
                message: message
            }).then(function(r) {
                if (handleServerResponse(r, function() {
                        showSuccess('メッセージを送信しました');
                    }));
            });
        }
    };

    // 查看好友历史
    c.viewFriendHistory = function(friend) {
        showSuccess('この機能は開発中です');
    };

    // 移除好友
    c.removeFriend = function(friend) {
        if (confirm(friend.display_name + ' を友達から削除しますか？')) {
            safeServerGet({
    action: 'remove_friend',
                friend_id: friend.user_id
            }).then(function(r) {
                if (handleServerResponse(r, function() {
                        c.selected_friend = null;
                        c.loadGuardianData();
                        showSuccess('友達を削除しました');
                    }));
            });
        }
    };

    // 实时更新好友状态
    var friendStatusInterval = null;

    function startFriendStatusPolling() {
        if (friendStatusInterval) return;

        friendStatusInterval = $interval(function() {
            if (c.show_guardian && c.data.friends && c.data.friends.length > 0) {
                c.server.get({
                    action: 'get_friend_status_updates'
                }).then(function(r) {
                    if (r && r.data && r.data.updates) {
                        r.data.updates.forEach(function(update) {
                            var friend = c.data.friends.find(function(f) {
                                return f.user_id === update.user_id;
                            });
                            if (friend) {
    var prevStatus = friend.heartbeat_status;
    friend.heartbeat_status = update.status;
    friend.last_heartbeat_time = update.time_ago;
    friend.current_zone = update.zone;

    // 状态恶化时通知
    if (prevStatus !== 'critical' && update.status === 'critical') {
        NotificationManager.show(
            '⚠️ ' + friend.display_name,
            '長時間応答がありません。安全を確認してください。',
            'critical'
        );
    }
}
                        });
                    }
                });
            }
        }, 30000);
    }

    function stopFriendStatusPolling() {
        if (friendStatusInterval) {
            $interval.cancel(friendStatusInterval);
            friendStatusInterval = null;
        }
    }

    $scope.$watch('c.show_guardian', function(newVal) {
        if (newVal) {
            startFriendStatusPolling();
        } else {
            stopFriendStatusPolling();
        }
    });

    $scope.$on('$destroy', function() {
        stopFriendStatusPolling();
    });

    // [新增] 汉堡菜单控制
    c.showMenu = false;
    c.toggleMenu = function() {
        c.showMenu = !c.showMenu;
    };

	// ==========================================
    // 使い方ガイド（Onboarding Tour） - 像素级精准重构版
    // ==========================================
    c.tour_active = false;
    c.current_tour_step = 0;
    c.tour_x = 0; c.tour_y = 0; c.tour_radius = 0;
    c.bubble_x = 0; c.bubble_y = 0;

    c.tour_steps = [
        { anchor: '#the-slime', title: '生存確認', content: 'こころちゃんをタップして、あなたの無事を知らせましょう。', position: 'bottom' },
        { anchor: '.sos-btn', title: '緊急SOS', content: '一刻を争う場合は、このボタンで即座に救助要請を送れます。', position: 'top' },
        { anchor: '.kokoro-menu-btn', title: 'メニュー', content: '履歴・守護の輪・安全設定はこちらに集約されています。', position: 'bottom' }
    ];

    // 动态生成绝对像素硬截断的遮罩，彻底消除渐变模糊
    c.getTourOverlayStyle = function() {
        if (!c.tour_active) return { 'display': 'none' };
        var r = c.tour_radius;
        var r_edge = r + 1; // 仅 1px 的物理边缘过滤，保证绝对清晰
        return {
            'background': 'radial-gradient(circle at ' + c.tour_x + 'px ' + c.tour_y + 'px, transparent ' + r + 'px, rgba(93, 64, 55, 0.7) ' + r_edge + 'px)'
        };
    };

    c.getTourBubbleStyle = function() {
        return {
            'top': c.bubble_y + 'px',
            'left': c.bubble_x + 'px'
        };
    };

    function updateTourPosition() {
        if (!c.tour_active) return;
        var step = c.tour_steps[c.current_tour_step];
        if (!step) return;

        var el = document.querySelector(step.anchor);
        var winW = $window.innerWidth;
        var winH = $window.innerHeight;
        var bubbleW = 250; // 气泡的固定物理宽度
        var bubbleH = 140; // 气泡的预估物理高度

        if (!el) {
            // DOM 未挂载时的屏幕居中安全降级
            c.tour_x = Math.round(winW / 2);
            c.tour_y = Math.round(winH / 2);
            c.tour_radius = 0;
            c.bubble_x = Math.round((winW - bubbleW) / 2);
            c.bubble_y = Math.round(winH / 2 + 20);
        } else {
            var rect = el.getBoundingClientRect();
            // 强制 Math.round 消除亚像素导致的边缘模糊
            c.tour_x = Math.round(rect.left + rect.width / 2);
            c.tour_y = Math.round(rect.top + rect.height / 2);
            c.tour_radius = Math.round(Math.max(rect.width, rect.height) / 1.5 + 15);

            c.bubble_x = Math.round(Math.max(15, Math.min(winW - bubbleW - 15, c.tour_x - bubbleW / 2)));

            // 动态物理碰撞检测：如果气泡超出版边，强制翻转位置
            if (step.position === 'top') {
                c.bubble_y = c.tour_y - c.tour_radius - bubbleH - 15;
                if (c.bubble_y < 15) c.bubble_y = c.tour_y + c.tour_radius + 20; 
            } else {
                c.bubble_y = c.tour_y + c.tour_radius + 20;
                if (c.bubble_y + bubbleH > winH) c.bubble_y = c.tour_y - c.tour_radius - bubbleH - 15; 
            }
        }
    }

    c.startTour = function($event) {
        if ($event) $event.stopPropagation();
        c.showMenu = false;
        if (c.step !== 0) {
            if (typeof NotificationManager !== 'undefined') {
                NotificationManager.show('ガイド開始不可', 'メイン画面でのみガイドを開始できます', 'warning');
            } else {
                showError('メイン画面でのみガイドを開始できます');
            }
            return;
        }

        c.tour_active = true;
        c.current_tour_step = 0;
        // 强制触发脏值检查与坐标更新
        $timeout(function() {
            updateTourPosition();
        }, 150);
    };

    c.nextTourStep = function($event) {
        if ($event) $event.stopPropagation();
        if (c.current_tour_step !== (c.tour_steps.length - 1)) {
            c.current_tour_step++;
            $timeout(updateTourPosition, 50);
        } else {
            c.tour_active = false;
        }
    };

    $window.addEventListener('resize', function() {
        if (c.tour_active) $timeout(updateTourPosition, 100);
    });

    // 状态初始化
    var CONFIG = {
        states: {
            DRAFT: 1,
            SUBMITTED: 10,
            ASSIGNED: 11,
            IN_PROGRESS: 2,
            COMPLETED: 4,
            CANCELLED: 5,
            ON_HOLD: 6
        },
        debounceDelay: 300
    };

    c.step = 0;
    c.is_poked = false;
    c.show_will_input = false;
    c.digital_will = "";
    c.current_state_val = 0;
    c.is_editing = false;
    c.submitting = false;
    c.saving = false;
    c.status_message = "待機中...";
    c.showSettings = false;
    c.current_heartbeat_id = null;
    c.ticket_number = "";
    c.ticket_sys_id = null;
    c.files = null;
    c.fileData = null;

    c.data.user_name = c.data.user_name || "お客様";

    c.temp_settings = {
            email: c.data.emergency_email || "",
            medical_info: c.data.medical_info || "",
            blood_type: c.data.blood_type || "",
            will: c.data.saved_will || "",
            daily_reminder: c.data.daily_reminder !== false
        };


	// ==========================================
// ★ タップ式フォーム — データ構造
// ==========================================
c.form = {
    location: '',
    detail_loc: '',
    severity: '',
    affected_count: '1',
    contact: '',
    remarks: '',
    needs: {
        water: false, food: false, medical: false, injury: false,
        baby: false, power: false, care: false, other: false
    }
};
c.showDetails = false;

c.hasAnyNeed = function() {
    var n = c.form.needs;
    return n.water || n.food || n.medical || n.injury ||
           n.baby || n.power || n.care || n.other;
};

// エリア選択 → 自動で次のステップへ
c.selectLocation = function(loc) {
    c.form.location = loc;
    if (c.step < 2) {
        $timeout(function() { c.step = 2; }, 200);
    }
};

// 困りごとトグル → 選択があれば次のステップへ
c.toggleNeed = function(key) {
    c.form.needs[key] = !c.form.needs[key];
    if (c.hasAnyNeed() && c.step < 3) {
        $timeout(function() { c.step = 3; }, 200);
    }
};

function _buildNeedsTags() {
    var tags = [];
    var n = c.form.needs;
    if (n.water)   tags.push('water');
    if (n.food)    tags.push('food');
    if (n.medical) tags.push('medical');
    if (n.injury)  tags.push('injury');
    if (n.baby)    tags.push('baby');
    if (n.power)   tags.push('power');
    if (n.care)    tags.push('care');
    if (n.other)   tags.push('other');
    return tags;
}

function _getPrimaryCategory(tags) {
    var priority = ['injury', 'medical', 'baby', 'care', 'water', 'food', 'power', 'other'];
    for (var i = 0; i < priority.length; i++) {
        if (tags.indexOf(priority[i]) !== -1) return priority[i];
    }
    return 'other';
}

function _severityToUrgency(severity) {
    return { 'safe': 'Low', 'struggling': 'Medium', 'critical': 'Critical' }[severity] || 'Medium';
}

    c.dict = {
    'Water': '飲料水',
    'Food': '食料',
    'Medical': '医療・薬',
    'Baby': '乳幼児用品',
    'Power': '電源・充電',
    'Other': 'その他',
    'Family Area': 'ファミリーエリア',
    'Single Area': '単身エリア',
    'Medical Area': '医療・ケアエリア',
    'Critical': '限界 (SOS)',
    'High': '困っている',
    'Medium': '普通',
    'Low': '急ぎません',
    // 增加一个兜底，处理空分类的情况
    '': '一般リクエスト' 
};

    c.statusDetails = {
        1: {
            icon: '📝',
            title: 'DRAFT',
            desc: '送信前の状態',
            nextStep: '送信してください'
        },
        10: {
            icon: '📨',
            title: 'SUBMITTED',
            desc: 'システムがリクエストを受信',
            nextStep: 'ボランティア確認待ち'
        },
        11: {
            icon: '🙋',
            title: 'ASSIGNED',
            desc: 'ボランティアが担当',
            nextStep: '配送準備中'
        },
        2: {
            icon: '🏃',
            title: 'IN_PROGRESS',
            desc: '救援物資を持って移動中',
            nextStep: 'まもなく到着'
        },
        4: {
            icon: '✅',
            title: 'COMPLETED',
            desc: 'お届け完了',
            nextStep: 'お大事に'
        },
        5: {
            icon: '❌',
            title: 'CANCELLED',
            desc: 'リクエストがキャンセルされました',
            nextStep: ''
        },
        6: {
            icon: '⏸️',
            title: 'ON_HOLD',
            desc: '一時停止',
            nextStep: '再開待ち'
        }
    };

    function showSuccess(msg) {
        spUtil.addInfoMessage(msg);
    }

    function showError(msg) {
        spUtil.addErrorMessage(msg || 'エラーが発生しました');
    }

    function handleServerResponse(response, successCallback) {
        if (!response || !response.data) {
            showError('サーバーエラー');
            return false;
        }
        if (response.data.error) {
            showError(response.data.error);
            return false;
        }
        if (successCallback) successCallback(response.data);
        return true;
    }

    c.goToVolunteerView = function() {
        $window.location.href = '?id=kokoro_volunteer';
    };
    // ==========================================
    // 眼睛跟随鼠标
    // ==========================================
    $scope.eyeX = 0;
    $scope.eyeY = 0;
    var targetEyeX = 0,
        targetEyeY = 0,
        eyeAnimationFrame = null;

    function animateEyes() {
        $scope.eyeX += (targetEyeX - $scope.eyeX) * 0.15;
        $scope.eyeY += (targetEyeY - $scope.eyeY) * 0.15;

        if (Math.abs(targetEyeX - $scope.eyeX) > 0.01 || Math.abs(targetEyeY - $scope.eyeY) > 0.01) {
            eyeAnimationFrame = requestAnimationFrame(function() {
                $scope.$apply();
                animateEyes();
            });
        } else {
            eyeAnimationFrame = null;
        }
    }

    function handleMouseMove(e) {
        var cx = $window.innerWidth / 2;
        var cy = $window.innerHeight / 2;
        var range = 8;
        targetEyeX = Math.max(Math.min((e.clientX - cx) / cx * range, range), -range);
        targetEyeY = Math.max(Math.min((e.clientY - cy) / cy * range, range * 0.5), -range * 0.5);
        if (!eyeAnimationFrame) {
            animateEyes();
        }
    }

    $window.addEventListener('mousemove', handleMouseMove);

	// ==========================================
// 应用内通知系统 (In-App Notification)
// ==========================================
c.notifications = [];
c.notification_count = 0;

var NotificationManager = {

    // 显示通知
    show: function(title, message, type, duration) {
        var notif = {
            id: Date.now(),
            title: title,
            message: message,
            type: type || 'info',  // info / success / warning / critical
            timestamp: new Date(),
            visible: true
        };

        $scope.$evalAsync(function() {
            c.notifications.unshift(notif);
            c.notification_count = c.notifications.length;

            // 最多保留5条
            if (c.notifications.length > 5) {
                c.notifications.pop();
            }
        });

        // 自动消失
        var autoDismiss = duration || 6000;
        if (type === 'critical') autoDismiss = 12000;

        $timeout(function() {
            NotificationManager.dismiss(notif.id);
        }, autoDismiss);

        return notif.id;
    },

    // 关闭通知
    dismiss: function(notifId) {
        $scope.$evalAsync(function() {
            for (var i = 0; i < c.notifications.length; i++) {
                if (c.notifications[i].id === notifId) {
                    c.notifications[i].visible = false;
                    break;
                }
            }

            // 延迟移除（等动画结束）
            $timeout(function() {
                c.notifications = c.notifications.filter(function(n) {
                    return n.visible;
                });
                c.notification_count = c.notifications.length;
            }, 400);
        });
    },

    // 清空所有
    clearAll: function() {
        $scope.$evalAsync(function() {
            c.notifications = [];
            c.notification_count = 0;
        });
    }
};

c.dismissNotification = function(notifId) {
    NotificationManager.dismiss(notifId);
};

	// ==========================================
// Offline Queue（オフラインキュー）
// ==========================================
c.network_status = 'online';  // online / offline / syncing
c.offline_queue_count = 0;
c.sync_progress = '';

var OfflineQueue = {
    STORAGE_KEY: 'kokoro_offline_queue',

    // 获取队列
    getQueue: function() {
        try {
            var raw = $window.localStorage.getItem(this.STORAGE_KEY);
            return raw ? JSON.parse(raw) : [];
        } catch (e) {
            return [];
        }
    },

    // 保存队列
    saveQueue: function(queue) {
        try {
            $window.localStorage.setItem(this.STORAGE_KEY, JSON.stringify(queue));
        } catch (e) {
            console.error('[Kokoro] Queue save error:', e);
        }
    },

    // 添加到队列
    enqueue: function(params) {
        var queue = this.getQueue();
        var item = {
            id: Date.now() + '_' + Math.random().toString(36).substr(2, 6),
            params: params,
            timestamp: new Date().toISOString(),
            retries: 0
        };
        queue.push(item);
        this.saveQueue(queue);
        this.updateCount();
        return item.id;
    },

    // 从队列移除
    dequeue: function(itemId) {
        var queue = this.getQueue();
        var filtered = [];
        for (var i = 0; i < queue.length; i++) {
            if (queue[i].id !== itemId) {
                filtered.push(queue[i]);
            }
        }
        this.saveQueue(filtered);
        this.updateCount();
    },

    // 更新计数
    updateCount: function() {
        $scope.$evalAsync(function() {
            c.offline_queue_count = OfflineQueue.getQueue().length;
        });
    },

    // 同步所有队列中的请求
    syncAll: function() {
        var queue = this.getQueue();
        if (queue.length === 0) return;

        $scope.$evalAsync(function() {
            c.network_status = 'syncing';
            c.sync_progress = '0/' + queue.length;
        });

        var completed = 0;
        var total = queue.length;
        var self = this;

        function processNext(index) {
            if (index >= total) {
                $scope.$evalAsync(function() {
                    c.network_status = 'online';
                    c.sync_progress = '';
                    self.updateCount();
                    if (completed > 0) {
                        showSuccess(completed + '件のリクエストを同期しました');
											NotificationManager.show(
    '📡 オフライン同期完了',
    completed + '件のリクエストをサーバーに送信しました',
    'success'
);
                    }
                });

                // 同步后刷新历史记录
                $timeout(function() {
                    c.server.get({
                        action: 'get_my_history',
                        guest_token: c.guest_token || ''
                    }).then(function(r) {
                        if (r && r.data && r.data.my_requests) {
                            c.data.my_requests = r.data.my_requests;
                        }
                    });
                }, 1000);

                return;
            }

            var item = queue[index];

            // 重新附加CSRF token
            item.params.csrf_token = csrfToken;

            c.server.get(item.params).then(function(response) {
                if (response && response.data && !response.data.error) {
                    self.dequeue(item.id);
                    completed++;
                }

                $scope.$evalAsync(function() {
                    c.sync_progress = (index + 1) + '/' + total;
                });

                // 间隔500ms发下一个，避免服务器过载
                $timeout(function() {
                    processNext(index + 1);
                }, 500);

            }).catch(function() {
                // 如果还是失败，增加重试次数
                item.retries = (item.retries || 0) + 1;

                // 超过3次放弃
                if (item.retries >= 3) {
                    self.dequeue(item.id);
                }

                $scope.$evalAsync(function() {
                    c.sync_progress = (index + 1) + '/' + total;
                });

                $timeout(function() {
                    processNext(index + 1);
                }, 1000);
            });
        }

        processNext(0);
    }
};

// 网络状态监听
function updateNetworkStatus() {
    $scope.$evalAsync(function() {
        if (navigator.onLine) {
            if (c.network_status === 'offline') {
                // 修复：先检查队列是否为空
                var queue = OfflineQueue.getQueue();

                if (queue.length > 0) {
                    // 有数据才显示同步中
                    c.network_status = 'syncing';
                    $timeout(function() {
                        OfflineQueue.syncAll();
                    }, 1500);
                } else {
                    // 没数据直接变回在线
                    c.network_status = 'online';
                }
            } else if (c.network_status !== 'syncing') {
                c.network_status = 'online';
            }
        } else {
            c.network_status = 'offline';
        }
    });
}

$window.addEventListener('online', updateNetworkStatus);
$window.addEventListener('offline', updateNetworkStatus);

// 初始化时检查队列
$timeout(function() {
    OfflineQueue.updateCount();
    if (navigator.onLine && OfflineQueue.getQueue().length > 0) {
        OfflineQueue.syncAll();
    }
}, 2000);

	// ==========================================
// CSRF 安全请求包装
// ==========================================
var csrfToken = c.data.csrf_token || '';

function safeServerGet(params) {
    params.csrf_token = csrfToken;

    // 离线时：关键操作存入队列
    if (!navigator.onLine) {
        var queueableActions = [
            'submit_record', 'submit_sos', 'register_heartbeat', 'update_will'
        ];

        if (params.action && queueableActions.indexOf(params.action) !== -1) {
            var queueId = OfflineQueue.enqueue(params);

            $scope.$evalAsync(function() {
                c.network_status = 'offline';
            });

            // 返回一个模拟的成功响应
            var deferred = {
                then: function(successCb) {
                    $timeout(function() {
                        successCb({
                            data: {
                                success: true,
                                offline_queued: true,
                                ticketNumber: 'OFFLINE-' + queueId.substr(0, 8),
                                newRecordID: queueId,
                                message: 'オフラインキューに保存されました'
                            }
                        });
                    }, 300);
                    return deferred;
                },
                catch: function() { return deferred; }
            };

            showSuccess('📡 オフライン - リクエストをキューに保存しました（ネットワーク復帰後に自動送信）');
            return deferred;
        }
    }

    // 在线时：正常发送
    return c.server.get(params);
}

	// ==========================================
// 一键SOS紧急功能
// ==========================================
c.sos_sending = false;
c.sos_location = null;

// 获取GPS位置（静默获取，不阻塞流程）
function getGPSLocation() {
    return new Promise(function(resolve) {
        if (!navigator.geolocation) {
            resolve(null);
            return;
        }

        var timeoutId = setTimeout(function() {
            resolve(null);
        }, 5000); // 5秒超时，灾区网络慢

        navigator.geolocation.getCurrentPosition(
            function(pos) {
                clearTimeout(timeoutId);
                resolve({
                    lat: pos.coords.latitude,
                    lng: pos.coords.longitude,
                    accuracy: Math.round(pos.coords.accuracy)
                });
            },
            function() {
                clearTimeout(timeoutId);
                resolve(null);
            },
            {
                enableHighAccuracy: false, // 省电优先
                timeout: 5000,
                maximumAge: 300000 // 5分钟缓存，减少GPS调用
            }
        );
    });
}

c.triggerSOS = function() {
    if (c.sos_sending) return;

    c.sos_sending = true;

    // 第1步：尝试获取GPS（不阻塞）
    getGPSLocation().then(function(location) {
        c.sos_location = location;

        // 第2步：构建SOS数据
        var sosData = {
            action: 'submit_sos',
            urgency: 'Critical',
            category: 'Other',
            quantity: 1,
            affected_count: '1',
            remarks: '【一键SOS】緊急救助要請',
            guest_token: c.guest_token || ''
        };

        // GPS成功时附加位置
        if (location) {
            sosData.detail_loc = 'GPS: ' + location.lat.toFixed(6) + ', ' + location.lng.toFixed(6) + 
                                 ' (精度' + location.accuracy + 'm)';
            sosData.gps_lat = location.lat;
            sosData.gps_lng = location.lng;
        } else {
            sosData.detail_loc = '位置不明 - 自動取得失敗';
        }

        // 安全設定から情報を自動付与
        if (c.data.emergency_email) {
            sosData.contact = c.data.emergency_email;
        }
        if (c.data.medical_info) {
            sosData.remarks += '\n【医療情報】' + c.data.medical_info;
        }
        if (c.data.blood_type) {
            sosData.remarks += '\n【血液型】' + c.data.blood_type;
        }

        // 第3步：送信
        safeServerGet(sosData).then(function(response) {
            $scope.$evalAsync(function() {
                c.sos_sending = false;

                if (response && response.data && response.data.success) {
                    c.ticket_number = response.data.ticketNumber;
                    c.ticket_sys_id = response.data.newRecordID;
                    c.data.location = 'SOS';
                    c.data.detail_loc = sosData.detail_loc;
                    c.data.category = 'Other';
                    c.data.quantity = 1;
                    c.data.urgency = 'Critical';
                    c.data.remarks = sosData.remarks;

                    if (response.data.my_requests) {
                        c.data.my_requests = response.data.my_requests;
                    }

                    // 直接跳到结果页
                    c.step = 5;
                    updateVisualState(CONFIG.states.SUBMITTED);

                    if (c.ticket_sys_id) {
                        initRecordWatcher(c.ticket_sys_id);
                    }

                    showSuccess('🆘 SOSを送信しました！救援チームに通知されました。');
									NotificationManager.show(
    '🆘 SOS送信完了',
    'リクエストID: ' + c.ticket_number + ' - 救援チームに通知済み',
    'critical'
);
                } else {
                    showError('SOS送信に失敗しました。通常の手順でリクエストしてください。');
                }
            });
        }).catch(function() {
            $scope.$evalAsync(function() {
                c.sos_sending = false;
                showError('通信エラー。再度お試しください。');
            });
        });
    });
};

