c.submitRequest = function() {
    if (!c.form.location || !c.hasAnyNeed() || !c.form.severity) return;

    c.submitting = true;

    var tags = _buildNeedsTags();
    var primaryCat = _getPrimaryCategory(tags);
    var urgency = _severityToUrgency(c.form.severity);

    var locationMap = {
        'family_area': 'Family Area',
        'general_area': 'Single Area',
        'medical_area': 'Medical Area',
        'other': 'Other'
    };

    safeServerGet({
        action: 'submit_record',
        location: locationMap[c.form.location] || c.form.location,
        category: primaryCat,
        needs_tags: tags.join(','),
        self_reported_severity: c.form.severity,
        urgency: urgency,
        detail_loc: c.form.detail_loc || '',
        affected_count: c.form.affected_count || '1',
        contact: c.form.contact || '',
        remarks: c.form.remarks || '',
        guest_token: c.guest_token || '',
        quantity: 1
    }).then(function(r) {
        if (!handleServerResponse(r, function(data) {
            c.ticket_number = data.ticketNumber;
            c.ticket_sys_id = data.newRecordID || null;
            if (data.my_requests) c.data.my_requests = data.my_requests;

            updateVisualState(CONFIG.states.SUBMITTED);
            if (c.ticket_sys_id) initRecordWatcher(c.ticket_sys_id);

            // 写真がある場合はアップロード
            if (c.fileData && c.ticket_sys_id) {
                uploadFile(c.ticket_sys_id);  // 既存関数（内部でfinishSubmitを呼ぶ）
            } else {
                c.step = 5;
            }

            showSuccess('リクエストを送信しました');
            NotificationManager.show(
                '📨 リクエスト送信完了',
                'ID: ' + c.ticket_number,
                'success'
            );
        })) {
            // エラー時
        }
        c.submitting = false;
    }).catch(function() {
        c.submitting = false;
        showError('通信エラー');
    });
};

