    // ==========================================
    // 文件上传
    // ==========================================
    c.uploadFiles = function(files) {
        if (!files || !files.length) return;
        var file = files[0];
        var allowedTypes = ['image/jpeg', 'image/png', 'image/gif', 'image/webp'];
        if (allowedTypes.indexOf(file.type) === -1) {
            showError('JPEG、PNG、GIF、WebP形式の画像のみ許可されています');
            return;
        }
        var maxSize = 5 * 1024 * 1024;
        if (file.size > maxSize) {
            showError('ファイルサイズは5MB以下にしてください');
            return;
        }
        c.files = file;
        var reader = new FileReader();
        reader.onload = function(e) {
            $scope.$apply(function() {
                c.fileData = e.target.result;
            });
        };
        reader.readAsDataURL(file);
    };

    c.clearFile = function() {
        c.files = null;
        c.fileData = null;
        var input = document.querySelector('input[type="file"]');
        if (input) input.value = '';
    };

    function uploadFile(sysId) {
        c.server.get({
            action: 'upload_attachment',
            sys_id: sysId,
            table: 'x_1821654_kokoro_0_silent_wish',
            file_name: c.files.name,
            file_data: c.fileData,
            content_type: c.files.type
        }).then(function() {
            finishSubmit(sysId);
        }).catch(function() {
            showError('アップロード失敗');
            finishSubmit(sysId);
        });
    }

