	 // ==========================================
// 历史记录逻辑 (完整修复版 - 避免 digest cycle 错误)
// ==========================================
c.show_history = false;

c.toggleHistory = function() {
    c.showMenu = false;  // 关闭汉堡菜单
    c.show_history = !c.show_history;

    if (c.show_history) {
        // 🔧 使用 $timeout 避免 $digest cycle 冲突
        $timeout(function() {
            c.server.get({
                action: 'get_my_history',
                guest_token: c.guest_token || ''
            }).then(function(r) {
               if (r && r.data && r.data.my_requests) {
                                // 直接赋值，Angular会自动检测
                                c.data.my_requests = r.data.my_requests;
                                console.log('✅ 历史记录已加载，数量:', c.data.my_requests.length);

                                // ★ 未完了の工単をリアルタイム監視 (直近10件のみ監視)
                                var activeItems = c.data.my_requests.filter(function(item) {
                                    return item.state != 4 && item.state != 5 && item.sys_id;
                                }).slice(0, 10);

                                activeItems.forEach(function(item) {
                                    initRecordWatcher(item.sys_id);
                                });
                            } else {
                                console.warn('⚠️ 未收到历史记录数据');
                            }
            }).catch(function(error) {
                console.error('❌ 加载历史记录失败:', error);
            });
        }, 0);
    }
};

c.loadTicket = function(item) {
    c.show_history = false;
    c.ticket_sys_id = item.sys_id;
    c.ticket_number = item.number;
    c.data.location = item.location;
    c.data.detail_loc = item.detail_loc;
    c.data.category = item.category;
    c.data.quantity = item.quantity;
    c.data.urgency = item.urgency;
    c.data.remarks = item.remarks;

    updateVisualState(item.state);
    initRecordWatcher(c.ticket_sys_id);
    c.step = 5;

    var slime = document.getElementById('the-slime');
    if (slime) slime.classList.add('happy-slime');
};


	// ==========================================
// 账户升级 (游客 → 注册用户)
// ==========================================
c.upgradeAccount = function() {
    if (!c.guest_token) {
        showError('ゲストトークンがありません');
        return;
    }

    c.server.get({
        action: 'upgrade_guest_account',
        guest_token: c.guest_token
    }).then(function(r) {
        if (handleServerResponse(r, function(data) {
            c.is_guest = false;
            c.auth_mode = 'authenticated';
            c.guest_token = '';

            try {
                $window.localStorage.removeItem('kokoro_guest_token');
            } catch (e) {}

            showSuccess(data.message || 'アカウントを移行しました');

            // 刷新数据
            c.server.get({
                action: 'get_my_history'
            }).then(function(historyR) {
                if (historyR && historyR.data && historyR.data.my_requests) {
                    c.data.my_requests = historyR.data.my_requests;
                }
            });
        }));
    });
};

// ==========================================
// 好友验证码 (灾后面对面)
// ==========================================
c.show_friend_code = false;
c.my_friend_code = '';
c.friend_code_input = '';

c.generateFriendCode = function() {
    safeServerGet({
    action: 'generate_friend_code'
    }).then(function(r) {
        if (handleServerResponse(r, function(data) {
            c.my_friend_code = data.friend_code;
            c.show_friend_code = true;
        }));
    });
};

c.verifyFriendCode = function() {
    if (!c.friend_code_input || c.friend_code_input.length !== 6) {
        showError('6桁のコードを入力してください');
        return;
    }

    safeServerGet({
    action: 'verify_friend_code',
        code: c.friend_code_input
    }).then(function(r) {
        if (handleServerResponse(r, function(data) {
            c.friend_code_input = '';
            c.show_friend_code = false;
            showSuccess(data.message);
            c.loadGuardianData();
        }));
    });
};

// ★ 初期ロード時にも未完了工単を監視開始 (直近10件のみ監視)
$timeout(function() {
    if (c.data.my_requests && c.data.my_requests.length > 0) {
        var activeItems = c.data.my_requests.filter(function(item) {
            return item.state != 4 && item.state != 5 && item.sys_id;
        }).slice(0, 10);

        activeItems.forEach(function(item) {
            initRecordWatcher(item.sys_id);
        });
    }
}, 1000);

$scope.$on('$destroy', function() {
    $window.removeEventListener('mousemove', handleMouseMove);
    $window.removeEventListener('online', updateNetworkStatus);
    $window.removeEventListener('offline', updateNetworkStatus);
    if (eyeAnimationFrame) {
        cancelAnimationFrame(eyeAnimationFrame);
    }
});

};

sp_widget.css:
@import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@400;500;700;900&family=M+PLUS+Rounded+1c:wght@400;500;700;800&display=swap');

/* ============================================================
   KOKORO USER - Widget CSS (Refugee Mode)
   Version: 3.4 (Heartbeat & Texture Fix)
   ============================================================ */

/* ==========================================
   1. 强制隐藏ServiceNow所有元素 (保持不变)
   ========================================== */
html body nav.navbar,
html body .navbar,
html body .navbar-inverse,
html body .navbar-default,
html body .navbar-header,
html body .sp-page-header,
html body header,
html body footer,
html body .sp-footer,
html body .footer,
html body .row.marketing-header,
html body #survey_plugin_container,
html body .navpage-header,
html body .navpage-header-content,
html body .sn-widget-textblock-body,
html body .breadcrumb-container,
html body [role="banner"],
html body .navbar-fixed-top,
html body .sp-row-background,
html body #gsft_main ~ header,
html body .polaris-navigation,
body > nav,
body > header,
body > footer,
#gsft_main > nav,
.sp-page-root > nav,
.sp-page-root > header {
  display: none !important;
  visibility: hidden !important;
  height: 0 !important;
  min-height: 0 !important;
  max-height: 0 !important;
  overflow: hidden !important;
  opacity: 0 !important;
  pointer-events: none !important;
  margin: 0 !important;
  padding: 0 !important;
  border: none !important;
  position: absolute !important;
  top: -9999px !important;
  left: -9999px !important;
}

html body,
html body .sp-page-root,
html body #sp-nav-bar {
  padding-top: 0 !important;
  margin-top: 0 !important;
}

/* ==========================================
   2. 主容器 - 背景 (保持不变)
   ========================================== */
.kokoro-user-container {
  font-family: "M PLUS Rounded 1c", sans-serif;
  position: fixed !important;
  top: 0 !important;
  left: 0 !important;
  right: 0 !important;
  bottom: 0 !important;
  width: 100vw !important;
  height: 100vh !important;
  z-index: 999999 !important;
  overflow: hidden;
  background: linear-gradient(180deg, #ffe4e1 0%, #fff0f0 40%, #fdf8f8 100%) !important;
}

/* ==========================================
   3. 史莱姆舞台 (保持不变)
   ========================================== */
.slime-stage {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  display: flex;
  justify-content: center;
  align-items: center;
  pointer-events: none;
  z-index: 1;
}

/* ==========================================
   4. 史莱姆 - 颜色与动画 (修改区域)
   ========================================== */
.kokoro-slime {
  width: 260px; /* 使用你提供的宽度 */
  height: 240px; /* 使用你提供的高度 */

/* [修改点] 加重了褐色调，减少了泛白，呈现出“做旧/褐色灰”的质感 */
  background: radial-gradient(circle at 30% 30%, #f5f0ef 0%, #d6c4bf 50%, #9e8982 100%);

  /* [修改点] 阴影也同步加深为暖褐色，增加体积感 */
  box-shadow: 
    0 20px 50px rgba(120, 100, 95, 0.4),
    inset 5px 5px 30px rgba(255, 255, 255, 0.6);

  border-radius: 60% 40% 30% 70% / 60% 30% 70% 40%;
  animation: slimeMorph 8s ease-in-out infinite;

  position: relative;
  margin-bottom: 280px;
  transform-origin: center bottom;
  cursor: pointer;
  pointer-events: auto !important;
  z-index: 100;

  transition: all 0.5s ease;
}

  /* 颜色过渡 */
  transition: all 0.5s ease;
}

/* ==========================================
   [新增] 汉堡菜单样式
   ========================================== */

/* 1. 悬浮按钮 (左上角) */
.kokoro-menu-btn {
  position: absolute;
  top: 20px;
  left: 20px;
  width: 50px;
  height: 50px;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.65);
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
  box-shadow: 0 8px 20px rgba(93, 64, 55, 0.15);
  border: 1px solid rgba(255, 255, 255, 0.8);
  display: flex;
  justify-content: center;
  align-items: center;
  font-size: 1.4rem;
  color: #880e4f;
  cursor: pointer;
  z-index: 2001; /* 必须比遮罩层高 */
  transition: all 0.3s cubic-bezier(0.4, 0.0, 0.2, 1);
}

.kokoro-menu-btn:hover {
  background: #fff;
  transform: scale(1.1);
  box-shadow: 0 10px 25px rgba(233, 30, 99, 0.25);
}

.kokoro-menu-btn.active {
  background: #fff;
  color: #ec407a;
  transform: rotate(90deg);
}

/* 2. 下拉菜单容器 */
.kokoro-menu-dropdown {
  position: absolute;
  top: 85px; /* 在按钮下方 */
  left: 20px;
  width: 260px;
  background: rgba(255, 255, 255, 0.85);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border-radius: 24px;
  padding: 12px;
  box-shadow: 0 15px 40px rgba(0, 0, 0, 0.1);
  border: 1px solid rgba(255, 255, 255, 0.6);
  z-index: 2000;
  animation: menuSlideIn 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
  transform-origin: top left;
}

/* 3. 菜单项 */
.menu-item {
  display: flex;
  align-items: center;
  padding: 12px 16px;
  margin-bottom: 6px;
  border-radius: 16px;
  cursor: pointer;
  transition: all 0.2s ease;
  position: relative;
}

.menu-item:last-child {
  margin-bottom: 0;
}

.menu-item:hover {
  background: rgba(255, 240, 245, 0.8); /* 浅粉色背景 */
}

/* 图标 */
.icon-box {
  width: 36px;
  height: 36px;
  background: #fff;
  border-radius: 12px;
  display: flex;
  justify-content: center;
  align-items: center;
  color: #ec407a;
  font-size: 1.1rem;
  margin-right: 14px;
  box-shadow: 0 4px 10px rgba(233, 30, 99, 0.1);
}

/* 文字 */
.text-box {
  flex: 1;
  display: flex;
  flex-direction: column;
}

.menu-title {
  font-weight: 800;
  color: #5d4037;
  font-size: 0.95rem;
}

.menu-sub {
  font-size: 0.7rem;
  color: #90a4ae;
  text-transform: uppercase;
  font-weight: 600;
  letter-spacing: 0.5px;
}

/* 数字角标 */
.badge-pill {
  background: #ff80ab;
  color: white;
  padding: 2px 8px;
  border-radius: 10px;
  font-size: 0.75rem;
  font-weight: 700;
}

/* 管理者高亮样式 */
.menu-item.highlight {
  background: linear-gradient(135deg, #fff3e0, #ffe0b2);
}
.menu-item.highlight .icon-box {
  color: #ff6f00;
}

/* 4. 点击空白关闭菜单的遮罩 */
.menu-backdrop {
  position: fixed;
  top: 0; left: 0; right: 0; bottom: 0;
  background: transparent; /* 透明，不妨碍视觉，只拦截点击 */
  z-index: 1999;
}

/* ==========================================
   守护圈 (Guardian Circle) 样式
   ========================================== */

/* 通知角标 - 红色警告 */
.badge-alert {
  background: #ff5252 !important;
  animation: badgePulse 2s infinite;
}

@keyframes badgePulse {
  0%, 100% { transform: scale(1); }
  50% { transform: scale(1.15); }
}

/* 主弹窗容器 */
.guardian-overlay {
  position: fixed;
  top: 0; left: 0; right: 0; bottom: 0;
  background: rgba(93, 64, 55, 0.35);
  backdrop-filter: blur(6px);
  display: flex;
  justify-content: center;
  align-items: center;
  z-index: 3000;
  animation: fadeIn 0.3s ease;
}

.guardian-card {
  background: #ffffff;
  width: 92%;
  max-width: 440px;
  max-height: 85vh;
  border-radius: 28px;
  box-shadow: 0 25px 60px rgba(0,0,0,0.15);
  display: flex;
  flex-direction: column;
  overflow: hidden;
  animation: slideUp 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

/* 渐变头部 */
.gradient-header {
  background: linear-gradient(135deg, #ec407a, #f48fb1);
  padding: 22px 24px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  color: white;
}

.gradient-header h3 {
  margin: 0;
  font-size: 1.3rem;
  font-weight: 800;
  display: flex;
  align-items: center;
  gap: 10px;
}

.gradient-header .close-btn {
  background: rgba(255,255,255,0.2);
  color: white;
  border: none;
  width: 34px;
  height: 34px;
  border-radius: 50%;
  font-size: 1.3rem;
  cursor: pointer;
  transition: all 0.2s;
}

.gradient-header .close-btn:hover {
  background: rgba(255,255,255,0.35);
  transform: rotate(90deg);
}

/* 标签栏 */
.tab-bar {
  display: flex;
  background: #fafafa;
  border-bottom: 2px solid #f0f0f0;
}

.tab-item {
  flex: 1;
  padding: 14px 10px;
  text-align: center;
  cursor: pointer;
  transition: all 0.2s;
  font-weight: 600;
  color: #757575;
  font-size: 0.9rem;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
  border-bottom: 3px solid transparent;
}

.tab-item i {
  font-size: 1.1rem;
}

.tab-item.active {
  color: #ec407a;
  background: white;
  border-bottom-color: #ec407a;
}

.tab-item:hover:not(.active) {
  background: #fff;
  color: #ec407a;
}

/* 内容区域 */
.tab-content {
  flex: 1;
  overflow-y: auto;
  padding: 16px 0;
  background: #fff;
}

/* 空状态 */
.empty-state {
  text-align: center;
  padding: 60px 20px;
  color: #999;
}

.empty-state i {
  color: #e0e0e0;
  margin-bottom: 20px;
}

.empty-state p {
  font-size: 1rem;
  margin-bottom: 20px;
}

/* 好友列表 */
.friend-list {
  padding: 0 16px;
}

.friend-card {
  display: flex;
  align-items: center;
  padding: 14px 16px;
  margin-bottom: 10px;
  background: #fafafa;
  border-radius: 18px;
  cursor: pointer;
  transition: all 0.2s;
  border: 2px solid transparent;
  position: relative;
}

.friend-card:hover {
  background: #fff5f8;
  border-color: #f8bbd0;
  transform: translateX(4px);
  box-shadow: 0 4px 12px rgba(236, 64, 122, 0.1);
}

/* 头像容器 */
.friend-avatar-wrapper {
  position: relative;
  margin-right: 14px;
  flex-shrink: 0;
}

.friend-avatar {
  width: 50px;
  height: 50px;
  border-radius: 50%;
  background: linear-gradient(135deg, #ff9a9e, #fad0c4);
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  font-size: 1.3rem;
  box-shadow: 0 4px 10px rgba(0,0,0,0.1);
}

/* 状态点 */
.status-dot {
  position: absolute;
  bottom: 0;
  right: 0;
  width: 16px;
  height: 16px;
  border-radius: 50%;
  border: 3px solid #fff;
  box-shadow: 0 2px 6px rgba(0,0,0,0.2);
}

.status-dot.online {
  background: #4caf50;
}

.status-dot.warning {
  background: #ff9800;
  animation: warningPulse 2s infinite;
}

.status-dot.critical {
  background: #f44336;
  animation: criticalPulse 1s infinite;
}

.status-dot.offline {
  background: #9e9e9e;
}

/* 脉冲动画 */
.pulse-ring {
  position: absolute;
  top: -3px;
  left: -3px;
  right: -3px;
  bottom: -3px;
  border-radius: 50%;
  border: 2px solid currentColor;
  animation: ringPulse 2s infinite;
  opacity: 0;
}

.status-dot.critical .pulse-ring {
  border-color: #f44336;
}

@keyframes ringPulse {
  0% { transform: scale(0.8); opacity: 0.8; }
  100% { transform: scale(1.5); opacity: 0; }
}

@keyframes warningPulse {
  0%, 100% { transform: scale(1); }
  50% { transform: scale(1.15); }
}

@keyframes criticalPulse {
  0%, 100% { transform: scale(1); box-shadow: 0 2px 6px rgba(244,67,54,0.3); }
  50% { transform: scale(1.2); box-shadow: 0 4px 12px rgba(244,67,54,0.6); }
}

/* 好友信息 */
.friend-info {
  flex: 1;
  min-width: 0;
}

.friend-name {
  font-weight: 800;
  color: #333;
  font-size: 1.05rem;
  margin-bottom: 4px;
  display: flex;
  align-items: center;
  gap: 8px;
}

.friend-badge {
  background: #fff3e0;
  color: #f57c00;
  padding: 2px 8px;
  border-radius: 8px;
  font-size: 0.7rem;
  font-weight: 700;
}

.friend-status-text,
.friend-location {
  font-size: 0.85rem;
  color: #757575;
  margin-top: 3px;
  display: flex;
  align-items: center;
  gap: 6px;
}

.friend-location {
  color: #ec407a;
  font-weight: 600;
}

/* 快捷按钮 */
.friend-actions {
  display: flex;
  gap: 8px;
  flex-shrink: 0;
}

.icon-btn {
  width: 38px;
  height: 38px;
  border-radius: 50%;
  border: none;
  background: #fff;
  color: #757575;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: all 0.2s;
  font-size: 1.1rem;
  box-shadow: 0 2px 6px rgba(0,0,0,0.08);
}

.icon-btn:hover {
  transform: scale(1.1);
}

.message-btn:hover {
  background: #e1f5fe;
  color: #0288d1;
}

.emergency-btn {
  background: #ffebee;
  color: #f44336;
  animation: emergencyShake 2s infinite;
}

.emergency-btn:hover {
  background: #f44336;
  color: white;
}

@keyframes emergencyShake {
  0%, 100% { transform: translateX(0); }
  25% { transform: translateX(-3px); }
  75% { transform: translateX(3px); }
}

/* 好友请求卡片 */
.request-list {
  padding: 0 16px;
}

.request-card {
  display: flex;
  align-items: center;
  padding: 16px;
  margin-bottom: 12px;
  background: #fff5f8;
  border-radius: 18px;
  border: 2px solid #fce4ec;
  animation: slideIn 0.3s ease;
}

.request-avatar {
  width: 50px;
  height: 50px;
  border-radius: 50%;
  background: linear-gradient(135deg, #ec407a, #f48fb1);
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  font-size: 1.3rem;
  margin-right: 14px;
  flex-shrink: 0;
}

.request-info {
  flex: 1;
  min-width: 0;
}

.request-name {
  font-weight: 800;
  color: #333;
  font-size: 1rem;
  margin-bottom: 4px;
}

.request-time {
  font-size: 0.8rem;
  color: #999;
  margin-bottom: 6px;
}

.request-message {
  font-size: 0.9rem;
  color: #666;
  font-style: italic;
  padding: 8px 12px;
  background: rgba(255,255,255,0.6);
  border-radius: 10px;
  margin-top: 6px;
}

.request-actions {
  display: flex;
  flex-direction: column;
  gap: 8px;
  flex-shrink: 0;
}

.btn-accept,
.btn-reject {
  padding: 8px 16px;
  border-radius: 16px;
  border: none;
  font-weight: 700;
  cursor: pointer;
  transition: all 0.2s;
  font-size: 0.9rem;
  display: flex;
  align-items: center;
  gap: 6px;
  white-space: nowrap;
}

.btn-accept {
  background: #4caf50;
  color: white;
}

.btn-accept:hover {
  background: #45a049;
  transform: scale(1.05);
}

.btn-reject {
  background: #fff;
  color: #f44336;
  border: 2px solid #ffcdd2;
}

.btn-reject:hover {
  background: #ffebee;
}

/* 搜索框 */
.search-box {
  margin: 16px;
  position: relative;
}

.search-box i {
  position: absolute;
  left: 18px;
  top: 50%;
  transform: translateY(-50%);
  color: #999;
  font-size: 1.1rem;
}

.search-input {
  width: 100%;
  padding: 14px 20px 14px 50px;
  border: 2px solid #f0f0f0;
  border-radius: 24px;
  font-size: 1rem;
  outline: none;
  transition: all 0.2s;
  font-family: inherit;
}

.search-input:focus {
  border-color: #ec407a;
  box-shadow: 0 0 0 4px rgba(236,64,122,0.1);
}

/* 搜索结果 */
.search-results {
  padding: 0 16px;
  margin-top: 10px;
}

.search-item {
  display: flex;
  align-items: center;
  padding: 12px;
  margin-bottom: 8px;
  background: #fafafa;
  border-radius: 16px;
  transition: all 0.2s;
}

.search-item:hover {
  background: #f5f5f5;
}

.search-avatar {
  width: 44px;
  height: 44px;
  border-radius: 50%;
  background: linear-gradient(135deg, #90caf9, #64b5f6);
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  font-size: 1.2rem;
  margin-right: 12px;
  flex-shrink: 0;
}

.search-info {
  flex: 1;
  min-width: 0;
}

.search-name {
  font-weight: 700;
  color: #333;
  font-size: 0.95rem;
}

.search-email,
.search-hint {
  font-size: 0.8rem;
  color: #999;
  margin-top: 2px;
}

.btn-add-friend {
  padding: 8px 18px;
  border-radius: 18px;
  border: none;
  background: linear-gradient(135deg, #ec407a, #f48fb1);
  color: white;
  font-weight: 700;
  cursor: pointer;
  transition: all 0.2s;
  font-size: 0.9rem;
  display: flex;
  align-items: center;
  gap: 6px;
  flex-shrink: 0;
}

.btn-add-friend:hover:not(:disabled) {
  transform: scale(1.05);
  box-shadow: 0 4px 12px rgba(236,64,122,0.3);
}

.btn-add-friend:disabled {
  background: #e0e0e0;
  color: #999;
  cursor: not-allowed;
}

/* 推荐区域 */
.recommended-section {
  margin-top: 24px;
  padding: 0 16px;
}

.section-title {
  font-size: 0.9rem;
  font-weight: 800;
  color: #757575;
  margin-bottom: 12px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

/* 好友详情弹窗 */
.friend-detail-overlay {
  position: fixed;
  top: 0; left: 0; right: 0; bottom: 0;
  background: rgba(93, 64, 55, 0.45);
  backdrop-filter: blur(8px);
  z-index: 3100;
  animation: fadeIn 0.3s ease;
  display: flex;
  justify-content: center;
  align-items: center;
}

.friend-detail-card {
  background: white;
  width: 90%;
  max-width: 400px;
  max-height: 85vh;
  border-radius: 28px;
  padding: 24px;
  overflow-y: auto;
  box-shadow: 0 30px 70px rgba(0,0,0,0.2);
  animation: slideUp 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
  position: relative;
}

.back-btn {
  position: absolute;
  top: 20px;
  left: 20px;
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background: rgba(255,255,255,0.9);
  border: 2px solid #f0f0f0;
  color: #333;
  font-size: 1.1rem;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.2s;
  z-index: 10;
}

.back-btn:hover {
  background: #f5f5f5;
  transform: scale(1.1);
}

.detail-header {
  text-align: center;
  padding-top: 20px;
  margin-bottom: 24px;
}

.detail-avatar-large {
  width: 90px;
  height: 90px;
  margin: 0 auto 16px;
  border-radius: 50%;
  background: linear-gradient(135deg, #ff9a9e, #fad0c4);
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  font-size: 2.5rem;
  box-shadow: 0 8px 20px rgba(0,0,0,0.15);
  position: relative;
}

.status-indicator {
  position: absolute;
  bottom: 5px;
  right: 5px;
  width: 22px;
  height: 22px;
  border-radius: 50%;
  border: 4px solid white;
  box-shadow: 0 2px 8px rgba(0,0,0,0.2);
}

.status-indicator.online { background: #4caf50; }
.status-indicator.warning { background: #ff9800; }
.status-indicator.critical { background: #f44336; }
.status-indicator.offline { background: #9e9e9e; }

.detail-header h3 {
  font-size: 1.4rem;
  margin: 0 0 8px 0;
  color: #333;
}

.detail-status-text {
  color: #757575;
  font-size: 0.95rem;
}

/* 统计信息 */
.detail-stats {
  display: flex;
  gap: 12px;
  margin-bottom: 24px;
}

.stat-item {
  flex: 1;
  background: #fafafa;
  padding: 14px;
  border-radius: 16px;
  text-align: center;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.stat-item i {
  font-size: 1.3rem;
  color: #ec407a;
  margin-bottom: 4px;
}

.stat-item span {
  font-size: 0.75rem;
  color: #999;
  text-transform: uppercase;
}

.stat-item strong {
  font-size: 0.9rem;
  color: #333;
  font-weight: 700;
}

/* 详情操作按钮 */
.detail-actions {
  display: flex;
  flex-direction: column;
  gap: 12px;
  margin-bottom: 24px;
}

.btn-action-large {
  width: 100%;
  padding: 14px 20px;
  border-radius: 20px;
  border: none;
  font-weight: 700;
  font-size: 1rem;
  cursor: pointer;
  transition: all 0.2s;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  font-family: inherit;
}

.btn-action-large.primary {
  background: linear-gradient(135deg, #ec407a, #f48fb1);
  color: white;
  box-shadow: 0 6px 16px rgba(236,64,122,0.3);
}

.btn-action-large.primary:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 20px rgba(236,64,122,0.4);
}

.btn-action-large.emergency {
  background: linear-gradient(135deg, #f44336, #e57373);
  color: white;
  box-shadow: 0 6px 16px rgba(244,67,54,0.3);
}

.btn-action-large.emergency:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 20px rgba(244,67,54,0.4);
}

.btn-action-large:not(.primary):not(.emergency) {
  background: #fafafa;
  color: #333;
  border: 2px solid #f0f0f0;
}

.btn-action-large:not(.primary):not(.emergency):hover {
  background: #f5f5f5;
}

/* 设置项 */
.detail-settings {
  background: #fafafa;
  border-radius: 18px;
  padding: 16px;
  margin-bottom: 16px;
}

.setting-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 12px 0;
  border-bottom: 1px solid #f0f0f0;
}

.setting-item:last-child {
  border-bottom: none;
}

.setting-item span {
  font-weight: 600;
  color: #333;
  font-size: 0.95rem;
}

/* Toggle开关 */
.toggle-switch {
  position: relative;
  width: 48px;
  height: 26px;
  display: inline-block;
}

.toggle-switch input {
  opacity: 0;
  width: 0;
  height: 0;
}

.slider {
  position: absolute;
  cursor: pointer;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background-color: #ccc;
  transition: 0.3s;
  border-radius: 26px;
}

.slider:before {
  position: absolute;
  content: "";
  height: 20px;
  width: 20px;
  left: 3px;
  bottom: 3px;
  background-color: white;
  transition: 0.3s;
  border-radius: 50%;
}

input:checked + .slider {
  background-color: #ec407a;
}

input:checked + .slider:before {
  transform: translateX(22px);
}

/* 删除按钮 */
.btn-danger-outline {
  width: 100%;
  padding: 12px;
  border-radius: 18px;
  border: 2px solid #ffcdd2;
  background: white;
  color: #f44336;
  font-weight: 700;
  cursor: pointer;
  transition: all 0.2s;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  font-family: inherit;
}

.btn-danger-outline:hover {
  background: #ffebee;
  border-color: #f44336;
}

/* 主要按钮（空状态） */
.btn-primary-small {
  padding: 10px 24px;
  border-radius: 20px;
  border: none;
  background: linear-gradient(135deg, #ec407a, #f48fb1);
  color: white;
  font-weight: 700;
  cursor: pointer;
  transition: all 0.2s;
  font-family: inherit;
}

.btn-primary-small:hover {
  transform: scale(1.05);
  box-shadow: 0 6px 16px rgba(236,64,122,0.3);
}

/* 响应式 */
@media (max-width: 480px) {
  .guardian-card {
    width: 96%;
    max-height: 90vh;
  }

  .friend-card {
    padding: 12px;
  }

  .friend-avatar {
    width: 44px;
    height: 44px;
    font-size: 1.1rem;
  }

  .status-dot {
    width: 14px;
    height: 14px;
  }
}

/* 动画 */
@keyframes menuSlideIn {
  from { opacity: 0; transform: scale(0.8) translateY(-20px); }
  to { opacity: 1; transform: scale(1) translateY(0); }
}

/* ==========================================
   KOKORO CSS 修复整合版
   ========================================== */

/* ------------------------------------------
   1. 汉堡菜单样式 (Menu)
   ------------------------------------------ */
.kokoro-menu-btn {
  position: absolute;
  top: 20px;
  left: 20px;
  width: 50px;
  height: 50px;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.65);
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
  box-shadow: 0 8px 20px rgba(93, 64, 55, 0.15);
  border: 1px solid rgba(255, 255, 255, 0.8);
  display: flex;
  justify-content: center;
  align-items: center;
  font-size: 1.4rem;
  color: #880e4f;
  cursor: pointer;
  z-index: 2001; /* 必须比遮罩高 */
  transition: all 0.3s cubic-bezier(0.4, 0.0, 0.2, 1);
}

.kokoro-menu-btn:hover {
  background: #fff;
  transform: scale(1.1);
  box-shadow: 0 10px 25px rgba(233, 30, 99, 0.25);
}

.kokoro-menu-btn.active {
  background: #fff;
  color: #ec407a;
  transform: rotate(90deg);
}

/* 下拉菜单容器 */
.kokoro-menu-dropdown {
  position: absolute;
  top: 85px;
  left: 20px;
  width: 260px;
  background: rgba(255, 255, 255, 0.95); /* 稍微不透明一点，防干扰 */
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border-radius: 24px;
  padding: 12px;
  box-shadow: 0 15px 40px rgba(0, 0, 0, 0.15);
  border: 1px solid rgba(255, 255, 255, 0.6);
  z-index: 2000;
  animation: menuSlideIn 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
  transform-origin: top left;
}

/* 菜单项 */
.menu-item {
  display: flex;
  align-items: center;
  padding: 12px 16px;
  margin-bottom: 6px;
  border-radius: 16px;
  cursor: pointer;
  transition: all 0.2s ease;
  position: relative;
}

.menu-item:last-child { margin-bottom: 0; }
.menu-item:hover { background: rgba(255, 240, 245, 0.8); }

.icon-box {
  width: 36px;
  height: 36px;
  background: #fff;
  border-radius: 12px;
  display: flex;
  justify-content: center;
  align-items: center;
  color: #ec407a;
  font-size: 1.1rem;
  margin-right: 14px;
  box-shadow: 0 4px 10px rgba(233, 30, 99, 0.1);
}

.text-box { flex: 1; display: flex; flex-direction: column; }
.menu-title { font-weight: 800; color: #5d4037; font-size: 0.95rem; }
.menu-sub { font-size: 0.7rem; color: #90a4ae; text-transform: uppercase; font-weight: 600; }
.badge-pill { background: #ff80ab; color: white; padding: 2px 8px; border-radius: 10px; font-size: 0.75rem; font-weight: 700; }
.menu-item.highlight { background: linear-gradient(135deg, #fff3e0, #ffe0b2); }
.menu-item.highlight .icon-box { color: #ff6f00; }

.menu-backdrop {
  position: fixed; top: 0; left: 0; right: 0; bottom: 0;
  background: transparent; z-index: 1999;
}

@keyframes menuSlideIn {
  from { opacity: 0; transform: scale(0.8) translateY(-20px); }
  to { opacity: 1; transform: scale(1) translateY(0); }
}


/* ------------------------------------------
   2. 申请履历弹窗样式 (History Overlay)
   这是你之前缺失的部分！一定要加上！
   ------------------------------------------ */
.history-overlay {
  position: fixed; /* 关键：固定定位 */
  top: 0; left: 0; right: 0; bottom: 0;
  background: rgba(93, 64, 55, 0.3); /* 遮罩层背景 */
  backdrop-filter: blur(4px);
  display: flex; 
  justify-content: center; 
  align-items: center;
  z-index: 3000; /* 关键：层级必须比菜单(2000)高 */
  animation: fadeIn 0.3s ease;
}

.history-card {
  background: #ffffff;
  width: 90%;
  max-width: 420px;
  border-radius: 24px;
  box-shadow: 0 25px 50px rgba(0,0,0,0.2);
  max-height: 80vh;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  border: 2px solid #fff0f5;
  animation: slideUp 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

.history-card .card-header {
  background: linear-gradient(to right, #fff0f5, #fff);
  padding: 20px 24px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  border-bottom: 1px solid #fce4ec;
}

.history-card .card-header h3 {
  margin: 0;
  color: #880e4f;
  font-size: 1.2rem;
  font-weight: 800;
  display: flex;
  align-items: center;
  gap: 10px;
}

.history-card .close-btn {
  background: #f8bbd0;
  color: #880e4f;
  border: none;
  width: 32px; height: 32px;
  border-radius: 50%;
  font-size: 1.2rem;
  line-height: 1;
  cursor: pointer;
  display: flex; justify-content: center; align-items: center;
  transition: all 0.2s;
}
.history-card .close-btn:hover { background: #ec407a; color: white; transform: rotate(90deg); }

.history-list { overflow-y: auto; padding: 10px 0; background: #fff; }

.history-item {
  display: flex; align-items: center;
  padding: 16px 24px;
  border-bottom: 1px dashed #fce4ec;
  cursor: pointer; transition: 0.2s;
}
.history-item:last-child { border-bottom: none; }
.history-item:hover { background: #fff5f8; padding-left: 28px; }

.item-icon {
  font-size: 1.4rem; margin-right: 15px;
  width: 40px; height: 40px;
  background: #fce4ec; border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  color: #ec407a;
}
.item-info { flex: 1; display: flex; flex-direction: column; }
.item-cat { font-weight: 700; color: #5d4037; font-size: 1rem; }
.item-date { font-size: 0.75rem; color: #90a4ae; margin-top: 4px; }

.item-status { 
  font-size: 0.75rem; font-weight: 700;
  padding: 4px 10px; border-radius: 12px; 
  background: #eceff1; color: #546e7a;
}
.status-1 { background: #e3f2fd; color: #1976d2; }
.status-10 { background: #e8f5e9; color: #2e7d32; }
.status-4 { background: #fff3e0; color: #f57c00; }

/* 眼睛 */
.slime-eyes {
  position: absolute;
  top: 40%;
  left: 50%;
  margin-left: -35px; /* 使用你提供的偏移 */
  width: 70px; /* 使用你提供的宽度 */
  height: 15px; /* 使用你提供的高度 */
  transition: transform 0.15s ease-out;
}

.slime-eyes::before,
.slime-eyes::after {
  content: '';
  position: absolute;
  top: 0;
  width: 14px; /* 使用你提供的尺寸 */
  height: 14px; /* 使用你提供的尺寸 */
  background: #5d4037;
  border-radius: 50%;
  animation: blink 4s infinite;
}

.slime-eyes::before { left: 0; }
.slime-eyes::after { right: 0; }

/* 隐藏嘴巴 (根据你提供的代码) */
.slime-mouth { display: none !important; }

/* 交互状态：Hover (恢复粉色) */
.kokoro-slime:hover {
  /* 恢复原本的粉色渐变 (根据你提供的代码) */
  background: radial-gradient(circle at 30% 30%, rgba(255,255,255,0.95), #ff9a9e);

  /* 恢复原本的鲜亮阴影 (根据你提供的代码) */
  box-shadow: 
    0 15px 50px rgba(255, 150, 150, 0.4),
    inset 5px 5px 30px rgba(255, 255, 255, 0.8);

  filter: saturate(1.1);
  transform: scale(1.02);
}

/* 交互状态：被戳中 (Poked) */
.kokoro-slime.poked {
  animation: gentleHeartbeat 0.6s ease-in-out forwards !important;

  /* 确保被戳中时也是粉色 */
  background: radial-gradient(circle at 30% 30%, rgba(255,255,255,0.95), #ff9a9e);
  box-shadow: 
    0 15px 50px rgba(255, 150, 150, 0.4),
    inset 5px 5px 30px rgba(255, 255, 255, 0.8);

  /* 稍微加深粉色，避免泛白 */
  filter: saturate(1.35) contrast(1.05);
}

/* 状态：饥饿/休眠 (保持灰褐色质感) */
.kokoro-slime.hungry-slime {
  /* 使用带有褐色/棕色调的浅灰褐色 */
  background: radial-gradient(circle at 30% 30%, #f8f6f4 0%, #e8e0da 50%, #c8b8b0 100%);
  box-shadow: 0 20px 50px rgba(160, 140, 130, 0.35), inset 5px 5px 30px rgba(255, 255, 255, 0.7);

  filter: saturate(0.4) brightness(0.95);
  transform: scale(0.9);
  animation: slimeMorph 10s ease-in-out infinite;
}

/* 状态：开心 (提交后) */
.kokoro-slime.happy-slime {
  /* 开心时变为粉色 */
  background: radial-gradient(circle at 30% 30%, rgba(255,255,255,0.95), #ff9a9e);
  box-shadow: 0 15px 50px rgba(255, 150, 150, 0.4), inset 5px 5px 30px rgba(255, 255, 255, 0.8);

  /* 心跳动画 */
  animation: happyJump 1.5s ease-in-out infinite;
  filter: saturate(1.2) brightness(1.05);
}

/* ==========================================
   5. 动画关键帧 (保持不变，使用新的happyJump)
   ========================================== */
@keyframes slimeMorph {
  0%, 100% {
    border-radius: 60% 40% 30% 70% / 60% 30% 70% 40%;
    transform: translate(0, 0) scale(1);
  }
  33% {
    border-radius: 50% 60% 40% 70% / 50% 60% 40% 60%;
    transform: translate(8px, -5px) scale(1.02, 0.98);
  }
  66% {
    border-radius: 70% 40% 60% 30% / 70% 40% 60% 30%;
    transform: translate(-8px, 5px) scale(0.98, 1.02);
  }
}

@keyframes gentleHeartbeat {
  0% { transform: scale(1); }
  15% { transform: scale(1.08); }
  30% { transform: scale(1); }
  45% { transform: scale(1.08); }
  60% { transform: scale(1); }
  100% { transform: scale(1); }
}

@keyframes happyJump {
  0%, 100% { 
    transform: scale(1); 
  }
  50% { 
    transform: scale(1.06); 
  }
}

@keyframes blink {
  0%, 96%, 100% { transform: scaleY(1); }
  98% { transform: scaleY(0.1); }
}

@keyframes popIn {
  from { opacity: 0; transform: scale(0.5); }
  to { opacity: 1; transform: scale(1); }
}

@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

@keyframes slideUp {
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
}

@keyframes pulse {
  0%, 100% { opacity: 1; transform: scale(1); }
  50% { opacity: 0.6; transform: scale(0.9); }
}

/* ==========================================
   6. UI组件 (保持原布局，适配新配色) - 以下部分均无修改
   ========================================== */

/* 设置按钮 */
.safety-settings-btn {
  position: absolute;
  top: 20px;
  left: 20px;
  background: rgba(255, 255, 255, 0.85);
