  gap: 6px;
}

.safety-settings-btn:hover {
  background: #fff;
  transform: translateY(-2px);
  box-shadow: 0 6px 16px rgba(0, 0, 0, 0.1);
}

.safety-settings-btn i { color: #ec407a; }

/* 管理者切换按钮 */
.admin-switch {
  position: absolute;
  top: 20px;
  right: 20px;
  opacity: 0.5;
  cursor: pointer;
  font-size: 2rem;
  z-index: 200;
