  transition: all 0.2s ease;
}

.admin-switch:hover { opacity: 1; }

/* 提示文字 */
.pulse-overlay {
  position: absolute;
  top: 15%;
  width: 100%;
  text-align: center;
  z-index: 5;
  animation: fadeIn 1.5s ease;
  pointer-events: none;
}

.pulse-title {
  font-size: 2.2rem;
  color: #5d4037;
  font-weight: 800;
  text-shadow: 0 4px 15px rgba(255, 255, 255, 0.9);
  letter-spacing: 2px;
}

.sub-text {
  font-size: 0.9rem;
  opacity: 0.7;
  font-weight: 600;
}

/* 表单容器 */
.form-stage {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  z-index: 10;
  overflow-y: auto;
  scroll-behavior: smooth;
  padding: 80px 20px 60px 20px;
  display: flex;
  flex-direction: column;
  align-items: center;
}

.floating-header {
  background: rgba(255, 255, 255, 0.95);
  backdrop-filter: blur(12px);
  padding: 22px 28px;
  border-radius: 26px;
  margin-bottom: 24px;
  box-shadow: 0 6px 24px rgba(0, 0, 0, 0.08);
